          "phases": [
            "EARLY_PHASE1"
          ],
          "designInfo": {
            "allocation": "NON_RANDOMIZED",
            "interventionModel": "SEQUENTIAL",
            "interventionModelDescription": "Initially, three patients per compound (89Zr-C9scFv and 89Zr-F8scFv) will be included according to alternating inclusion or patient availability (n=6). Subsequently, an interim analysis will be conducted to determine the optimal radiation dose and optimal scanning day for each radiolabeled antibody fragment.\n\nAfter the interim analysis, cohorts will be expanded with additional solid tumor indications and will include 13 more subjects per compound (n=26), resulting in 32 subjects overall. This basket trial aims to include at least one patient per indication.\n\nFor expansion cohort subjects, IMP-administration will occur on day 1, with one PET/CT scan performed on the most optimal day (this was determined to be day 4). Optionally, patients can receive an additional day 6 scan to gain more insight into tumor retention.",
            "primaryPurpose": "OTHER",
            "maskingInfo": {
