        "armsInterventionsModule": {
          "armGroups": [
            {
              "label": "89Zr-F8scFv",
              "type": "EXPERIMENTAL",
              "description": "The first 3 patients of this arm will receive a single i.v. microdose (1 mg) administration of 89Zr-F8scFv 15 MBq, followed by three whole-body PET/CT scans on day 1, 2 and 4. After the first three patients, an interim analysis will be conducted to determine the optimal scanning time point and radiation dose.\n\nThe following 13 patients will receive a single i.v. microdose administration of 89Zr-F8scFv between 15 - 30 MBq, followed by one whole-body PET/CT scan on the optimal scanning day (day 1-7). Each subject will have a follow-up visit approximately 28 days after IMP administration.",
              "interventionNames": [
                "Biological: 89Zr-DFO-N-Suc-F8scFv",
                "Radiation: PET/CT scan"
              ]
            },
            {
              "label": "89Zr-C9scFv",
              "type": "EXPERIMENTAL",
              "description": "The first 3 patients of this arm will receive a single i.v. microdose (1 mg) administration of 89Zr-C9scFv 15 MBq, followed by three whole-body PET/CT scans on day 1, 2 and 4. After the first three patients, an interim analysis will be conducted to determine the optimal scanning time point and radiation dose.\n\nThe following 13 patients will receive a single i.v. microdose administration of 89Zr-C9scFv between 15 - 30 MBq, followed by one whole-body PET/CT scan on the optimal scanning day (day 1-7). Each subject will have a follow-up visit approximately 28 days after IMP administration.",
              "interventionNames": [
                "Biological: 89Zr-DFO-N-Suc-C9scFv",
                "Radiation: PET/CT scan"
              ]
            }
